INSERT INTO `blogs` VALUES (1,'Kiến thức - Kinh nghiệm - Trải nghiệm','kien-thuc-kinh-nghiem-trai-nghiem','Tháng Năm về, sắc đỏ phượng vĩ lại thắp lửa trên những vòm lá, gợi nhắc về một thời thanh xuân rực rỡ. Cùng lật lại những trang lưu bút và tìm về ký ức tuổi học trò nằm ngủ quên trong ngăn bàn cũ.','<h2>Mùa&nbsp;Phượng&nbsp;Cuối&nbsp;Và&nbsp;Những&nbsp;Ngăn&nbsp;Bàn&nbsp;Chứa&nbsp;Đầy&nbsp;Nắng</h2><p>Có&nbsp;một&nbsp;loài&nbsp;hoa&nbsp;không&nbsp;cần&nbsp;hương&nbsp;thơm&nbsp;ngào&nbsp;ngạt&nbsp;để&nbsp;người&nbsp;ta&nbsp;nhớ&nbsp;đến,&nbsp;cũng&nbsp;chẳng&nbsp;cần&nbsp;sự&nbsp;chăm&nbsp;sóc&nbsp;cầu&nbsp;kỳ&nbsp;để&nbsp;vươn&nbsp;mình&nbsp;rực&nbsp;rỡ.&nbsp;Đó&nbsp;là&nbsp;<strong>Hoa&nbsp;Học&nbsp;Trò</strong>&nbsp;–&nbsp;loài&nbsp;hoa&nbsp;phượng&nbsp;vĩ&nbsp;đỏ&nbsp;rực&nbsp;một&nbsp;góc&nbsp;trời,&nbsp;loài&nbsp;hoa&nbsp;mang&nbsp;cả&nbsp;định&nbsp;nghĩa&nbsp;về&nbsp;một&nbsp;thời&nbsp;thanh&nbsp;xuân&nbsp;rực&nbsp;rỡ&nbsp;nhất.</p><h3>1.&nbsp;Khi&nbsp;sắc&nbsp;đỏ&nbsp;bắt&nbsp;đầu&nbsp;&quot;thì&nbsp;thầm&quot;</h3><p>Tháng&nbsp;Năm&nbsp;về,&nbsp;tiếng&nbsp;ve&nbsp;bắt&nbsp;đầu&nbsp;râm&nbsp;ran&nbsp;trên&nbsp;những&nbsp;vòm&nbsp;lá&nbsp;cũng&nbsp;là&nbsp;lúc&nbsp;những&nbsp;chùm&nbsp;phượng&nbsp;vĩ&nbsp;đầu&nbsp;tiên&nbsp;&quot;thắp&nbsp;lửa&quot;.&nbsp;Với&nbsp;nhiều&nbsp;người,&nbsp;màu&nbsp;đỏ&nbsp;của&nbsp;phượng&nbsp;là&nbsp;màu&nbsp;của&nbsp;mùa&nbsp;hè&nbsp;rực&nbsp;rỡ,&nbsp;nhưng&nbsp;với&nbsp;đám&nbsp;học&nbsp;trò&nbsp;chúng&nbsp;mình,&nbsp;đó&nbsp;lại&nbsp;là&nbsp;màu&nbsp;của&nbsp;<strong>sự&nbsp;chia&nbsp;xa</strong>.</p><p>Bạn&nbsp;có&nbsp;nhớ&nbsp;cảm&nbsp;giác&nbsp;lén&nbsp;lút&nbsp;ép&nbsp;một&nbsp;cánh&nbsp;hoa&nbsp;phượng&nbsp;vào&nbsp;trang&nbsp;vở,&nbsp;nắn&nbsp;nót&nbsp;tạo&nbsp;hình&nbsp;thành&nbsp;một&nbsp;chú&nbsp;bướm&nbsp;xinh&nbsp;xắn&nbsp;không?&nbsp;Những&nbsp;cánh&nbsp;hoa&nbsp;ấy&nbsp;không&nbsp;chỉ&nbsp;là&nbsp;kỷ&nbsp;niệm,&nbsp;mà&nbsp;còn&nbsp;là&nbsp;minh&nbsp;chứng&nbsp;cho&nbsp;những&nbsp;lời&nbsp;hứa&nbsp;&quot;giữ&nbsp;liên&nbsp;lạc&nbsp;nhé&quot;&nbsp;mà&nbsp;đôi&nbsp;khi&nbsp;thời&nbsp;gian&nbsp;vô&nbsp;tình&nbsp;làm&nbsp;phai&nbsp;mờ.</p><h3>2.&nbsp;Những&nbsp;ngăn&nbsp;bàn&nbsp;không&nbsp;chỉ&nbsp;đựng&nbsp;sách&nbsp;vở</h3><p>Trong&nbsp;những&nbsp;ngày&nbsp;cuối&nbsp;cấp&nbsp;này,&nbsp;ngăn&nbsp;bàn&nbsp;dường&nbsp;như&nbsp;chật&nbsp;chội&nbsp;hơn.&nbsp;Nó&nbsp;không&nbsp;chỉ&nbsp;chứa&nbsp;những&nbsp;cuốn&nbsp;sách&nbsp;giáo&nbsp;khoa&nbsp;dày&nbsp;cộp&nbsp;hay&nbsp;những&nbsp;tờ&nbsp;nháp&nbsp;kín&nbsp;mít&nbsp;công&nbsp;thức&nbsp;Toán&nbsp;học,&nbsp;mà&nbsp;còn&nbsp;chứa&nbsp;đựng:</p><ul><li><strong>Những&nbsp;mẩu&nbsp;giấy&nbsp;chuyền&nbsp;tay:</strong>&nbsp;Những&nbsp;dòng&nbsp;chữ&nbsp;viết&nbsp;vội,&nbsp;những&nbsp;lời&nbsp;hỏi&nbsp;thăm&nbsp;ngô&nbsp;nghê.</li><li><strong>Những&nbsp;chiếc&nbsp;bút&nbsp;hết&nbsp;mực:</strong>&nbsp;Ghi&nbsp;dấu&nbsp;bao&nbsp;giờ&nbsp;kiểm&nbsp;tra&nbsp;căng&nbsp;thẳng.</li><li><strong>Và&nbsp;cả&nbsp;những&nbsp;&quot;bí&nbsp;mật&quot;:</strong>&nbsp;Một&nbsp;cái&nbsp;tên&nbsp;ai&nbsp;đó&nbsp;được&nbsp;viết&nbsp;nắn&nbsp;nót&nbsp;rồi&nbsp;lại&nbsp;xóa&nbsp;đi.</li></ul><p><img src=\"data:image/jpeg;base64,\"></p><h3>3.&nbsp;Đừng&nbsp;để&nbsp;mùa&nbsp;hạ&nbsp;trôi&nbsp;đi&nbsp;trong&nbsp;nuối&nbsp;tiếc</h3><p>Người&nbsp;ta&nbsp;nói,&nbsp;thanh&nbsp;xuân&nbsp;giống&nbsp;như&nbsp;một&nbsp;cơn&nbsp;mưa&nbsp;rào,&nbsp;dù&nbsp;bạn&nbsp;có&nbsp;từng&nbsp;bị&nbsp;cảm&nbsp;lạnh&nbsp;vì&nbsp;tắm&nbsp;mưa,&nbsp;bạn&nbsp;vẫn&nbsp;muốn&nbsp;được&nbsp;đắm&nbsp;mình&nbsp;trong&nbsp;nó&nbsp;một&nbsp;lần&nbsp;nữa.&nbsp;Hoa&nbsp;học&nbsp;trò&nbsp;nở&nbsp;rồi&nbsp;sẽ&nbsp;tàn,&nbsp;nhưng&nbsp;những&nbsp;năm&nbsp;tháng&nbsp;ngồi&nbsp;trên&nbsp;ghế&nbsp;nhà&nbsp;trường&nbsp;là&nbsp;độc&nbsp;nhất.</p><p>&quot;Chúng&nbsp;ta&nbsp;của&nbsp;năm&nbsp;17&nbsp;tuổi,&nbsp;có&nbsp;thể&nbsp;chưa&nbsp;có&nbsp;gì&nbsp;trong&nbsp;tay,&nbsp;nhưng&nbsp;lại&nbsp;có&nbsp;cả&nbsp;thế&nbsp;giới&nbsp;trong&nbsp;lòng.&quot;</p><p><strong>Gửi&nbsp;bạn,&nbsp;người&nbsp;đang&nbsp;đọc&nbsp;những&nbsp;dòng&nbsp;này:</strong>&nbsp;Nếu&nbsp;bạn&nbsp;vẫn&nbsp;còn&nbsp;đang&nbsp;được&nbsp;ngồi&nbsp;dưới&nbsp;bóng&nbsp;cây&nbsp;phượng&nbsp;vĩ,&nbsp;hãy&nbsp;trân&nbsp;trọng&nbsp;từng&nbsp;phút&nbsp;giây&nbsp;nhé.&nbsp;Hãy&nbsp;cứ&nbsp;cười&nbsp;thật&nbsp;tươi,&nbsp;hãy&nbsp;cứ&nbsp;can&nbsp;đảm&nbsp;nói&nbsp;lời&nbsp;cảm&nbsp;ơn&nbsp;với&nbsp;thầy&nbsp;cô&nbsp;và&nbsp;lời&nbsp;chào&nbsp;với&nbsp;người&nbsp;bạn&nbsp;thầm&nbsp;mến.&nbsp;Để&nbsp;khi&nbsp;sắc&nbsp;đỏ&nbsp;kia&nbsp;khép&nbsp;lại,&nbsp;chúng&nbsp;ta&nbsp;không&nbsp;phải&nbsp;ngoảnh&nbsp;lại&nbsp;và&nbsp;nói&nbsp;hai&nbsp;chữ&nbsp;&quot;giá&nbsp;như&quot;.</p>','http://localhost:8080/assets/images/ckeditor/1777105365113_hoahoctro.jpg','kien-thuc','Hoa Học Trò',1,'2026-04-25 07:44:18','2026-04-25 07:44:18','2026-04-25 08:22:45'),(7,'Những Cơn Mưa Rào Tuổi 17 Và Chiếc Áo Trắng Bay Trong Gió','nhung-con-mua-rao-tuoi-17-va-chiec-ao-trang-bay-trong-gio','Có ai đó đã từng ví von rằng: \"Thanh xuân giống như một cơn mưa rào, dù cho bạn từng bị cảm lạnh vì tắm mưa, bạn vẫn muốn được đắm mình trong nó một lần nữa.\"','<h3>1.&nbsp;Cơn&nbsp;mưa&nbsp;bất&nbsp;chợt&nbsp;dưới&nbsp;mái&nbsp;hiên&nbsp;trường</h3><p>Mùa&nbsp;hạ&nbsp;của&nbsp;tuổi&nbsp;học&nbsp;trò&nbsp;không&nbsp;chỉ&nbsp;có&nbsp;nắng&nbsp;cháy&nbsp;sân&nbsp;trường&nbsp;hay&nbsp;tiếng&nbsp;ve&nbsp;kêu&nbsp;râm&nbsp;ran,&nbsp;mà&nbsp;còn&nbsp;là&nbsp;những&nbsp;cơn&nbsp;mưa&nbsp;rào&nbsp;đến&nbsp;nhanh&nbsp;và&nbsp;đi&nbsp;cũng&nbsp;vội.&nbsp;Đó&nbsp;là&nbsp;những&nbsp;lần&nbsp;cả&nbsp;đám&nbsp;tụm&nbsp;ba&nbsp;tụm&nbsp;bảy&nbsp;dưới&nbsp;mái&nbsp;hiên,&nbsp;chờ&nbsp;mưa&nbsp;ngớt&nbsp;để&nbsp;cùng&nbsp;nhau&nbsp;đạp&nbsp;xe&nbsp;về,&nbsp;vừa&nbsp;đi&nbsp;vừa&nbsp;té&nbsp;nước&nbsp;trêu&nbsp;đùa&nbsp;nhau.&nbsp;Những&nbsp;giọt&nbsp;nước&nbsp;mưa&nbsp;làm&nbsp;ướt&nbsp;nhòe&nbsp;trang&nbsp;vở,&nbsp;nhưng&nbsp;lại&nbsp;làm&nbsp;tươi&nbsp;mát&nbsp;những&nbsp;nụ&nbsp;cười&nbsp;hồn&nbsp;nhiên&nbsp;nhất.</p><p><img src=\"http://localhost:8080/assets/images/ckeditor/1777986794109_blog5.jpg\" alt=\"hihi\" title=\"hihi\"></p><h3>2.&nbsp;Sắc&nbsp;trắng&nbsp;tinh&nbsp;khôi&nbsp;giữa&nbsp;trời&nbsp;mưa&nbsp;hạ</h3><p>Chiếc&nbsp;áo&nbsp;đồng&nbsp;phục&nbsp;trắng&nbsp;tinh&nbsp;khôi&nbsp;chính&nbsp;là&nbsp;biểu&nbsp;tượng&nbsp;đẹp&nbsp;nhất&nbsp;của&nbsp;thời&nbsp;học&nbsp;sinh.&nbsp;Trong&nbsp;làn&nbsp;mưa&nbsp;trắng&nbsp;xóa,&nbsp;những&nbsp;tà&nbsp;áo&nbsp;dài&nbsp;hay&nbsp;chiếc&nbsp;sơ&nbsp;mi&nbsp;trắng&nbsp;ấy&nbsp;vẫn&nbsp;luôn&nbsp;là&nbsp;hình&nbsp;ảnh&nbsp;khiến&nbsp;trái&nbsp;tim&nbsp;ai&nbsp;đó&nbsp;lỗi&nbsp;nhịp.&nbsp;Màu&nbsp;trắng&nbsp;ấy&nbsp;không&nbsp;chỉ&nbsp;là&nbsp;trang&nbsp;phục,&nbsp;mà&nbsp;là&nbsp;sự&nbsp;thuần&nbsp;khiết,&nbsp;là&nbsp;khoảng&nbsp;thời&nbsp;gian&nbsp;mà&nbsp;chúng&nbsp;ta&nbsp;lo&nbsp;lắng&nbsp;về&nbsp;một&nbsp;bài&nbsp;kiểm&nbsp;tra&nbsp;khó&nbsp;nhiều&nbsp;hơn&nbsp;là&nbsp;những&nbsp;bộn&nbsp;bề&nbsp;của&nbsp;cuộc&nbsp;sống&nbsp;sau&nbsp;này.</p><h3>3.&nbsp;Lời&nbsp;hứa&nbsp;dưới&nbsp;cơn&nbsp;mưa</h3><p>Mưa&nbsp;mùa&nbsp;hạ&nbsp;thường&nbsp;gắn&nbsp;liền&nbsp;với&nbsp;những&nbsp;lời&nbsp;chia&nbsp;tay.&nbsp;Có&nbsp;những&nbsp;lời&nbsp;hứa&nbsp;sẽ&nbsp;mãi&nbsp;là&nbsp;bạn&nbsp;thân,&nbsp;có&nbsp;những&nbsp;tình&nbsp;cảm&nbsp;chớm&nbsp;nở&nbsp;chưa&nbsp;kịp&nbsp;đặt&nbsp;tên&nbsp;đã&nbsp;phải&nbsp;khép&nbsp;lại&nbsp;theo&nbsp;tiếng&nbsp;trống&nbsp;trường&nbsp;kết&nbsp;thúc&nbsp;năm&nbsp;học.&nbsp;Cơn&nbsp;mưa&nbsp;ấy&nbsp;vô&nbsp;tình&nbsp;che&nbsp;đi&nbsp;những&nbsp;giọt&nbsp;nước&nbsp;mắt&nbsp;lăn&nbsp;dài&nbsp;ngày&nbsp;tốt&nbsp;nghiệp,&nbsp;để&nbsp;chúng&nbsp;ta&nbsp;mạnh&nbsp;mẽ&nbsp;bước&nbsp;tiếp&nbsp;trên&nbsp;con&nbsp;đường&nbsp;riêng.</p>','http://localhost:8080/assets/images/ckeditor/1777460588400_blog1.jpg','kinh-nghiem','Hoa Học Trò',1,'2026-04-29 11:03:08','2026-04-29 11:03:08','2026-05-05 13:13:25'),(8,'Tiếng Ve Gọi Nắng Và Những Bản Tình Ca Viết Dở','tieng-ve-goi-nang-va-nhung-ban-tinh-ca-viet-do','Nếu phượng vĩ là màu sắc, thì tiếng ve chính là \"âm thanh định danh\" của mùa hè. Có những ngày nắng gắt, tiếng ve râm ran khiến ta thấy đôi chút ồn ào, nhưng khi xa rồi, đó lại là giai điệu khiến lòng người thổn thức nhất mỗi khi nhớ về thời đi học.','<h3><span style=\"font-size: 1.5rem;\">1.&nbsp;Bản&nbsp;nhạc&nbsp;không&nbsp;lời&nbsp;trên&nbsp;vòm&nbsp;lá</span></h3><p>Tiếng&nbsp;ve&nbsp;không&nbsp;bắt&nbsp;đầu&nbsp;một&nbsp;cách&nbsp;từ&nbsp;tốn,&nbsp;nó&nbsp;luôn&nbsp;đồng&nbsp;loạt&nbsp;và&nbsp;mạnh&nbsp;mẽ&nbsp;như&nbsp;nhiệt&nbsp;huyết&nbsp;của&nbsp;tuổi&nbsp;trẻ.&nbsp;Với&nbsp;đám&nbsp;học&nbsp;trò,&nbsp;tiếng&nbsp;ve&nbsp;là&nbsp;tín&nbsp;hiệu&nbsp;của&nbsp;những&nbsp;kỳ&nbsp;nghỉ&nbsp;dài,&nbsp;của&nbsp;những&nbsp;chuyến&nbsp;đi&nbsp;chơi&nbsp;xa,&nbsp;nhưng&nbsp;cũng&nbsp;là&nbsp;hồi&nbsp;chuông&nbsp;báo&nbsp;hiệu&nbsp;thời&nbsp;gian&nbsp;bên&nbsp;nhau&nbsp;đang&nbsp;ngắn&nbsp;lại.&nbsp;Những&nbsp;trưa&nbsp;hè&nbsp;trốn&nbsp;ngủ,&nbsp;ngồi&nbsp;nghe&nbsp;tiếng&nbsp;ve&nbsp;vang&nbsp;lên&nbsp;giữa&nbsp;không&nbsp;gian&nbsp;tĩnh&nbsp;lặng,&nbsp;ta&nbsp;mới&nbsp;chợt&nbsp;nhận&nbsp;ra&nbsp;mùa&nbsp;hạ&nbsp;đã&nbsp;chạm&nbsp;đến&nbsp;từng&nbsp;ngóc&nbsp;ngách&nbsp;của&nbsp;hành&nbsp;lang&nbsp;lớp&nbsp;học.</p><h3><span style=\"font-size: 1.5rem;\">2.&nbsp;Cuốn&nbsp;lưu&nbsp;bút&nbsp;và&nbsp;những&nbsp;dòng&nbsp;chữ&nbsp;chưa&nbsp;kịp&nbsp;ráo&nbsp;mực</span></h3><p>Mùa&nbsp;hạ&nbsp;là&nbsp;mùa&nbsp;của&nbsp;những&nbsp;cuốn&nbsp;lưu&nbsp;bút&nbsp;chuyền&nbsp;tay.&nbsp;<a href=\"https://www.youtube.com/watch?v=RbYUmXU7x2o\" rel=\"noopener noreferrer\" target=\"_blank\">Giữa&nbsp;tiếng&nbsp;ve&nbsp;kêu&nbsp;râm&nbsp;ran</a>,&nbsp;chúng&nbsp;ta&nbsp;hối&nbsp;hả&nbsp;ghi&nbsp;lại&nbsp;cho&nbsp;nhau&nbsp;số&nbsp;điện&nbsp;thoại,&nbsp;địa&nbsp;chỉ&nbsp;nhà,&nbsp;hay&nbsp;những&nbsp;lời&nbsp;chúc&nbsp;thành&nbsp;công&nbsp;đầy&nbsp;hy&nbsp;vọng.</p><p>Có&nbsp;những&nbsp;trang&nbsp;lưu&nbsp;bút&nbsp;được&nbsp;viết&nbsp;rất&nbsp;dài,&nbsp;nhưng&nbsp;cũng&nbsp;có&nbsp;những&nbsp;trang&nbsp;chỉ&nbsp;vỏn&nbsp;vẹn&nbsp;một&nbsp;câu&nbsp;nói,&nbsp;một&nbsp;hình&nbsp;vẽ&nbsp;nghệch&nbsp;ngoạc.&nbsp;Đó&nbsp;là&nbsp;nơi&nbsp;cất&nbsp;giữ&nbsp;những&nbsp;&quot;bản&nbsp;tình&nbsp;ca&nbsp;viết&nbsp;dở&quot;&nbsp;–&nbsp;những&nbsp;tình&nbsp;cảm&nbsp;ngây&nbsp;ngô&nbsp;chưa&nbsp;bao&nbsp;giờ&nbsp;dám&nbsp;ngỏ&nbsp;lời,&nbsp;chỉ&nbsp;biết&nbsp;gửi&nbsp;gắm&nbsp;vào&nbsp;âm&nbsp;thanh&nbsp;của&nbsp;mùa&nbsp;hạ.</p><p><img src=\"http://localhost:8080/assets/images/ckeditor/1777708016665_blog5.jpg\" alt=\"hihihihihi\" title=\"hihihihihi\"></p><h3><span style=\"font-size: 1.5rem;\">3.&nbsp;Sau&nbsp;tiếng&nbsp;ve&nbsp;là&nbsp;những&nbsp;khoảng&nbsp;trời&nbsp;riêng</span></h3><p>Khi&nbsp;tiếng&nbsp;ve&nbsp;thưa&nbsp;dần&nbsp;cũng&nbsp;là&nbsp;lúc&nbsp;chúng&nbsp;ta&nbsp;phải&nbsp;rẽ&nbsp;sang&nbsp;những&nbsp;ngả&nbsp;đường&nbsp;khác&nbsp;nhau.&nbsp;Sân&nbsp;trường&nbsp;sẽ&nbsp;trở&nbsp;lại&nbsp;vẻ&nbsp;yên&nbsp;tĩnh&nbsp;vốn&nbsp;có,&nbsp;cây&nbsp;bàng,&nbsp;cây&nbsp;phượng&nbsp;vẫn&nbsp;đứng&nbsp;đó,&nbsp;chỉ&nbsp;có&nbsp;người&nbsp;là&nbsp;đi&nbsp;xa.&nbsp;Tiếng&nbsp;ve&nbsp;năm&nbsp;sau&nbsp;vẫn&nbsp;sẽ&nbsp;kêu,&nbsp;nhưng&nbsp;người&nbsp;cùng&nbsp;ngồi&nbsp;nghe&nbsp;tiếng&nbsp;ve&nbsp;năm&nbsp;ấy&nbsp;giờ&nbsp;đã&nbsp;trưởng&nbsp;thành&nbsp;và&nbsp;theo&nbsp;đuổi&nbsp;những&nbsp;giấc&nbsp;mơ&nbsp;riêng.</p>','http://localhost:8080/assets/images/ckeditor/1777460717882_blog4.jpg','kien-thuc','Hoa Học Trò',1,'2026-04-29 11:05:17','2026-04-29 11:05:17','2026-05-07 18:51:43');
/*!40000 ALTER TABLE `blogs` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `configs`
--

DROP TABLE IF EXISTS `configs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `configs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `key` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `content` text COLLATE utf8mb4_general_ci,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `type` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `musicName` char(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `section` varchar(255) COLLATE utf8mb4_general_ci DEFAULT 'general',
