INSERT INTO `configs` VALUES (1,'logo','assets\\images\\configs\\Birds_and_nest.gif','2026-01-28 09:23:22','2025-02-26 15:14:23','image',NULL,'general'),(5,'textDecription','<p><span style=\"font-family: arial;\">Một&nbsp;buổi&nbsp;học&nbsp;hiệu&nbsp;quả&nbsp;luôn&nbsp;bắt&nbsp;đầu&nbsp;từ&nbsp;một&nbsp;không&nbsp;gian&nbsp;phù&nbsp;hợp.&nbsp;Hoa&nbsp;Học&nbsp;Trò&nbsp;mang&nbsp;đến&nbsp;dịch&nbsp;vụ&nbsp;cho&nbsp;thuê&nbsp;phòng&nbsp;dạy&nbsp;học&nbsp;tại&nbsp;Đà&nbsp;Nẵng,&nbsp;dành&nbsp;cho&nbsp;giáo&nbsp;viên,&nbsp;gia&nbsp;sư&nbsp;và&nbsp;các&nbsp;đơn&nbsp;vị&nbsp;đào&nbsp;tạo&nbsp;đang&nbsp;tìm&nbsp;kiếm&nbsp;một&nbsp;nơi&nbsp;giảng&nbsp;dạy&nbsp;ổn&nbsp;định,&nbsp;gọn&nbsp;gàng&nbsp;và&nbsp;sẵn&nbsp;sàng&nbsp;sử&nbsp;dụng&nbsp;ngay.&nbsp;</span></p><p><span style=\"font-family: arial;\">Không&nbsp;cần&nbsp;đầu&nbsp;tư&nbsp;phòng&nbsp;ốc&nbsp;hay&nbsp;lo&nbsp;lắng&nbsp;khâu&nbsp;chuẩn&nbsp;bị,&nbsp;mỗi&nbsp;phòng&nbsp;dạy&nbsp;học&nbsp;cho&nbsp;thuê&nbsp;tại&nbsp;Hoa&nbsp;Học&nbsp;Trò&nbsp;đều&nbsp;được&nbsp;trang&nbsp;bị&nbsp;đầy&nbsp;đủ&nbsp;bàn&nbsp;ghế&nbsp;tiêu&nbsp;chuẩn,&nbsp;bảng&nbsp;viết,&nbsp;điều&nbsp;hòa,&nbsp;tivi,&nbsp;hệ&nbsp;thống&nbsp;ánh&nbsp;sáng&nbsp;phù&nbsp;hợp&nbsp;học&nbsp;tập&nbsp;cùng&nbsp;wifi&nbsp;ổn&nbsp;định.&nbsp;Bạn&nbsp;chỉ&nbsp;cần&nbsp;mang&nbsp;theo&nbsp;bài&nbsp;giảng,&nbsp;phần&nbsp;không&nbsp;gian&nbsp;và&nbsp;tiện&nbsp;nghi&nbsp;đã&nbsp;được&nbsp;chuẩn&nbsp;bị&nbsp;sẵn&nbsp;để&nbsp;buổi&nbsp;học&nbsp;diễn&nbsp;ra&nbsp;trọn&nbsp;vẹn.&nbsp;</span></p><p><span style=\"font-family: arial;\">Dù&nbsp;là&nbsp;lớp&nbsp;học&nbsp;kèm&nbsp;ít&nbsp;người,&nbsp;lớp&nbsp;kỹ&nbsp;năng&nbsp;ngắn&nbsp;hạn&nbsp;hay&nbsp;lớp&nbsp;học&nbsp;cố&nbsp;định&nbsp;theo&nbsp;ca,&nbsp;không&nbsp;gian&nbsp;phòng&nbsp;học&nbsp;cho&nbsp;thuê&nbsp;tại&nbsp;Hoa&nbsp;Học&nbsp;Trò&nbsp;luôn&nbsp;được&nbsp;sắp&nbsp;xếp&nbsp;linh&nbsp;hoạt&nbsp;theo&nbsp;nhu&nbsp;cầu&nbsp;thực&nbsp;tế,&nbsp;giúp&nbsp;bạn&nbsp;chủ&nbsp;động&nbsp;hơn&nbsp;trong&nbsp;việc&nbsp;tổ&nbsp;chức&nbsp;và&nbsp;duy&nbsp;trì&nbsp;chất&nbsp;lượng&nbsp;giảng&nbsp;dạy&nbsp;lâu&nbsp;dài.&nbsp;</span></p>','2026-01-05 09:23:36','2026-05-05 08:38:18','richtext',NULL,'about'),(6,'bgTitle','assets/images/configs/ÄuÌÌng tiÌm ÄaÌu xa nuÌÌa ..PNG','2026-01-01 09:23:42','2026-04-23 12:46:25','image',NULL,'about'),(7,'linkfb','https://www.facebook.com/phongdayhocchothue.hoahoctro.danang/','2026-01-01 09:23:45','2026-01-01 09:23:48','text',NULL,'general'),(8,'linkMess','https://www.facebook.com/messages/t/392234097613470','2026-01-01 09:23:51','2026-01-01 09:23:54','text',NULL,'general'),(9,'linkYoutube','https://www.youtube.com/channel/UCOPijTagF3kOO9G7tXctp0w','2026-01-01 09:23:57','2026-01-01 09:23:59','text',NULL,'general'),(10,'imgContact','assets/images/configs/Web lieÌn heÌ£Ì.png.PNG','2026-01-01 09:24:07','2025-09-02 02:41:29','image',NULL,'general'),(11,'nurseryImg','assets/images/configs/ThieÌÌt keÌÌ chuÌa coÌ teÌn.PNG','2026-01-01 09:24:10','2025-09-06 07:15:58','image',NULL,'general'),(12,'nurseryTitle','Chào mừng bạn đến với nhà Trò, nơi dành cho tất cả mọi người.','2026-01-01 09:24:13','2025-07-17 10:20:05','text',NULL,'general'),(13,'nameBrand','CHOTHUÊPHÒNGDẠYHỌC \r\nĐÀNẴNG•HOAHOCTROCO.','2026-01-01 09:24:16','2025-09-15 17:52:33','text','','general'),(14,'address','54 Lê Đình Lý - Đà Nẵng, 70 Phạm Văn Nghị - Đà Nẵng','2026-01-01 09:24:23','2025-09-08 07:26:53','text',NULL,'general'),(15,'phone','0931939120','2026-01-01 09:24:26','2025-09-05 07:47:03','text',NULL,'general'),(16,'email','trungtamhoahoctro@gmail.com','2026-01-01 09:24:29','2025-04-03 14:46:53','text',NULL,'general'),(17,'zalo','https://zalo.me/0337165122','2026-01-01 09:24:34','2026-01-01 09:24:31','text',NULL,'general'),(18,'googleMap','https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3834.1561041160007!2d108.20870597505312!3d16.05738718462034!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x314219b6590f00d7%3A0xb65cf388ddcb4a7a!2zNTQgTMOqIMSQw6xuaCBMw70sIFRo4bqhYyBHacOhbiwgVGhhbmggS2jDqiwgxJDDoCBO4bq1bmcgNTUwMDAwLCBWaeG7h3QgTmFt!5e0!3m2!1svi!2s!4v1757951630032!5m2!1svi!2s','2026-01-01 09:24:37','2025-09-15 15:56:31','text','','general'),(19,'background','assets/images/configs/bg-new.PNG','2025-03-16 16:19:47','2026-01-08 17:01:03','image','','general'),(20,'linkNotication','https://www.facebook.com/phongdayhocchothue.hoahoctro.danang','2025-03-23 17:08:59','2025-07-17 10:21:32','text',NULL,'general'),(21,'textNotication','Đến fanpage để khám phá phòng học ở khu vực mới!','2025-03-23 17:08:59','2025-09-15 17:48:26','text','','general'),(23,'color-bg','#fff9eb','2025-08-17 16:30:31','2025-08-30 09:39:06','color',NULL,'general'),(24,'color-bg-footer','#271d17','2025-08-17 17:07:15','2025-09-01 17:56:42','color',NULL,'general'),(25,'logo-page-detail','assets\\images\\configs\\Birds_and_nest.gif','2025-08-19 22:58:35','2025-02-26 15:14:23','image',NULL,'general'),(26,'icon-goc','assets/images/configs/IMG_2402.gif','2025-09-02 12:32:45','2025-09-15 19:31:14','image','','general'),(27,'home-music','assets/images/configs/Love whispers.mp3','2025-09-14 18:00:47','2026-01-09 10:59:34','music','Bản nhạc này tựa như bầu không khí ở nhà Trò… Hy vọng bạn sẽ tìm được căn phòng học ưng ý!','general'),(28,'googleVerification','b3A0XmC0sMKv4ipwabeBCt8QZa2Kauzh4RVDR2OpwLw','2026-01-06 03:30:44','2026-01-06 04:43:09','text','','general'),(30,'faq_list','[{\"question\":\"<p>Hoa&nbsp;Học&nbsp;Trò&nbsp;cho&nbsp;thuê&nbsp;phòng&nbsp;dạy&nbsp;học&nbsp;với&nbsp;giá&nbsp;bao&nbsp;nhiêu?</p>\",\"answer\":\"<p>Hiện&nbsp;tại,&nbsp;Hoa&nbsp;Học&nbsp;Trò&nbsp;áp&nbsp;dụng&nbsp;một&nbsp;mức&nbsp;giá&nbsp;duy&nbsp;nhất&nbsp;80.000&nbsp;VNĐ&nbsp;mỗi&nbsp;giờ,&nbsp;sử&nbsp;dụng&nbsp;cho&nbsp;tất&nbsp;cả&nbsp;các&nbsp;phòng&nbsp;học&nbsp;và&nbsp;mọi&nbsp;quy&nbsp;mô&nbsp;lớp&nbsp;học.&nbsp;Mức&nbsp;giá&nbsp;đã&nbsp;bao&nbsp;gồm&nbsp;đầy&nbsp;đủ&nbsp;tiện&nbsp;nghi,&nbsp;không&nbsp;phát&nbsp;sinh&nbsp;thêm&nbsp;chi&nbsp;phí&nbsp;trong&nbsp;quá&nbsp;trình&nbsp;sử&nbsp;dụng.</p>\"},{\"question\":\"<p>Giá&nbsp;thuê&nbsp;80.000&nbsp;VNĐ/giờ&nbsp;đã&nbsp;bao&nbsp;gồm&nbsp;những&nbsp;tiện&nbsp;ích&nbsp;gì?</p>\",\"answer\":\"<p>Chi&nbsp;phí&nbsp;thuê&nbsp;phòng&nbsp;đã&nbsp;bao&nbsp;gồm&nbsp;bàn&nbsp;ghế&nbsp;tiêu&nbsp;chuẩn,&nbsp;bảng&nbsp;viết,&nbsp;điều&nbsp;hòa,&nbsp;tivi&nbsp;hỗ&nbsp;trợ&nbsp;trình&nbsp;chiếu,&nbsp;hệ&nbsp;thống&nbsp;ánh&nbsp;sáng&nbsp;phù&nbsp;hợp&nbsp;cho&nbsp;việc&nbsp;học&nbsp;và&nbsp;wifi&nbsp;tốc&nbsp;độ&nbsp;cao.&nbsp;Phòng&nbsp;học&nbsp;được&nbsp;chuẩn&nbsp;bị&nbsp;sẵn&nbsp;sàng&nbsp;trước&nbsp;mỗi&nbsp;ca,&nbsp;bạn&nbsp;chỉ&nbsp;cần&nbsp;đến&nbsp;và&nbsp;bắt&nbsp;đầu&nbsp;buổi&nbsp;giảng&nbsp;dạy.</p>\"},{\"question\":\"<p>Hoa&nbsp;Học&nbsp;Trò&nbsp;có&nbsp;những&nbsp;phòng&nbsp;học&nbsp;quy&nbsp;mô&nbsp;như&nbsp;thế&nbsp;nào?</p>\",\"answer\":\"<p>Hoa&nbsp;Học&nbsp;Trò&nbsp;cung&nbsp;cấp&nbsp;nhiều&nbsp;phòng&nbsp;học&nbsp;với&nbsp;quy&nbsp;mô&nbsp;đa&nbsp;dạng,&nbsp;phù&nbsp;hợp&nbsp;từ&nbsp;lớp&nbsp;kèm&nbsp;ít&nbsp;người&nbsp;đến&nbsp;các&nbsp;lớp&nbsp;học&nbsp;đông&nbsp;học&nbsp;viên.&nbsp;Không&nbsp;gian&nbsp;được&nbsp;sắp&nbsp;xếp&nbsp;linh&nbsp;hoạt&nbsp;để&nbsp;đáp&nbsp;ứng&nbsp;nhiều&nbsp;hình&nbsp;thức&nbsp;giảng&nbsp;dạy&nbsp;khác&nbsp;nhau.</p>\"},{\"question\":\"<p>Có&nbsp;thể&nbsp;thuê&nbsp;phòng&nbsp;theo&nbsp;giờ&nbsp;hay&nbsp;theo&nbsp;ca&nbsp;cố&nbsp;định&nbsp;không?</p>\",\"answer\":\"<p>Bạn&nbsp;có&nbsp;thể&nbsp;thuê&nbsp;phòng&nbsp;theo&nbsp;giờ&nbsp;linh&nbsp;hoạt&nbsp;hoặc&nbsp;sắp&nbsp;xếp&nbsp;lịch&nbsp;thuê&nbsp;cố&nbsp;định&nbsp;theo&nbsp;ca&nbsp;cho&nbsp;các&nbsp;lớp&nbsp;học&nbsp;dài&nbsp;hạn.&nbsp;Điều&nbsp;này&nbsp;giúp&nbsp;giáo&nbsp;viên&nbsp;và&nbsp;đơn&nbsp;vị&nbsp;đào&nbsp;tạo&nbsp;chủ&nbsp;động&nbsp;hơn&nbsp;trong&nbsp;việc&nbsp;tổ&nbsp;chức&nbsp;và&nbsp;duy&nbsp;trì&nbsp;lớp&nbsp;học.</p>\"},{\"question\":\"<p>Phòng&nbsp;học&nbsp;có&nbsp;phù&nbsp;hợp&nbsp;cho&nbsp;lớp&nbsp;học&nbsp;kỹ&nbsp;năng&nbsp;hoặc&nbsp;đào&nbsp;tạo&nbsp;ngắn&nbsp;hạn&nbsp;không?</p>\",\"answer\":\"<p>Không&nbsp;gian&nbsp;phòng&nbsp;học&nbsp;tại&nbsp;Hoa&nbsp;Học&nbsp;Trò&nbsp;phù&nbsp;hợp&nbsp;cho&nbsp;lớp&nbsp;học&nbsp;kèm,&nbsp;lớp&nbsp;kỹ&nbsp;năng,&nbsp;lớp&nbsp;đào&nbsp;tạo&nbsp;ngắn&nbsp;hạn&nbsp;cũng&nbsp;như&nbsp;các&nbsp;lớp&nbsp;học&nbsp;cố&nbsp;định.&nbsp;Trang&nbsp;thiết&nbsp;bị&nbsp;và&nbsp;cách&nbsp;bố&nbsp;trí&nbsp;được&nbsp;tối&nbsp;ưu&nbsp;cho&nbsp;việc&nbsp;giảng&nbsp;dạy&nbsp;và&nbsp;tương&nbsp;tác.</p>\"},{\"question\":\"<p>Cần&nbsp;chuẩn&nbsp;bị&nbsp;gì&nbsp;khi&nbsp;đến&nbsp;thuê&nbsp;phòng&nbsp;dạy&nbsp;học?</p>\",\"answer\":\"<p>Bạn&nbsp;chỉ&nbsp;cần&nbsp;mang&nbsp;theo&nbsp;nội&nbsp;dung&nbsp;bài&nbsp;giảng&nbsp;và&nbsp;học&nbsp;viên.&nbsp;Mọi&nbsp;yếu&nbsp;tố&nbsp;về&nbsp;không&nbsp;gian&nbsp;và&nbsp;thiết&nbsp;bị&nbsp;phục&nbsp;vụ&nbsp;giảng&nbsp;dạy&nbsp;đã&nbsp;được&nbsp;Hoa&nbsp;Học&nbsp;Trò&nbsp;chuẩn&nbsp;bị&nbsp;sẵn&nbsp;để&nbsp;buổi&nbsp;học&nbsp;diễn&nbsp;ra&nbsp;suôn&nbsp;sẻ.</p>\"},{\"question\":\"<p>Nếu&nbsp;lớp&nbsp;học&nbsp;kéo&nbsp;dài&nbsp;hơn&nbsp;thời&nbsp;gian&nbsp;dự&nbsp;kiến&nbsp;thì&nbsp;tính&nbsp;phí&nbsp;như&nbsp;thế&nbsp;nào?</p>\",\"answer\":\"<p>Thời&nbsp;gian&nbsp;sử&nbsp;dụng&nbsp;phòng&nbsp;được&nbsp;tính&nbsp;theo&nbsp;số&nbsp;giờ&nbsp;thực&nbsp;tế,&nbsp;giúp&nbsp;bạn&nbsp;linh&nbsp;hoạt&nbsp;trong&nbsp;quá&nbsp;trình&nbsp;giảng&nbsp;dạy&nbsp;mà&nbsp;không&nbsp;lo&nbsp;phát&nbsp;sinh&nbsp;không&nbsp;rõ&nbsp;ràng.</p>\"},{\"question\":\"<p>Có&nbsp;chỗ&nbsp;gửi&nbsp;xe&nbsp;cho&nbsp;giáo&nbsp;viên&nbsp;và&nbsp;học&nbsp;viên&nbsp;không?</p>\",\"answer\":\"<p>Hoa&nbsp;Học&nbsp;Trò&nbsp;hỗ&nbsp;trợ&nbsp;khu&nbsp;vực&nbsp;gửi&nbsp;xe&nbsp;miễn&nbsp;phí,&nbsp;giúp&nbsp;giáo&nbsp;viên&nbsp;và&nbsp;học&nbsp;viên&nbsp;yên&nbsp;tâm&nbsp;khi&nbsp;đến&nbsp;học.</p>\"},{\"question\":\"<p>Hoa&nbsp;Học&nbsp;Trò&nbsp;có&nbsp;những&nbsp;cơ&nbsp;sở&nbsp;nào&nbsp;tại&nbsp;Đà&nbsp;Nẵng?</p>\",\"answer\":\"<p>Hiện&nbsp;tại,&nbsp;Hoa&nbsp;Học&nbsp;Trò&nbsp;có&nbsp;2&nbsp;cơ&nbsp;sở&nbsp;cho&nbsp;thuê&nbsp;phòng&nbsp;dạy&nbsp;học&nbsp;tại&nbsp;Đà&nbsp;Nẵng,&nbsp;đặt&nbsp;tại&nbsp;54&nbsp;Lê&nbsp;Đình&nbsp;Lý&nbsp;và&nbsp;70&nbsp;Phạm&nbsp;Văn&nbsp;Nghị.&nbsp;Cả&nbsp;hai&nbsp;địa&nbsp;điểm&nbsp;đều&nbsp;thuận&nbsp;tiện&nbsp;di&nbsp;chuyển,&nbsp;phù&nbsp;hợp&nbsp;cho&nbsp;giáo&nbsp;viên&nbsp;và&nbsp;học&nbsp;viên&nbsp;trong&nbsp;khu&nbsp;vực&nbsp;trung&nbsp;tâm&nbsp;thành&nbsp;phố.</p>\"},{\"question\":\"<p>2eeq</p>\",\"answer\":\"<p>ưqeqwewqe</p>\"}]','2026-04-17 16:59:01','2026-04-29 09:32:35','text',NULL,'general'),(32,'describe-heading','<h1><span style=\"font-size: 6.5rem; font-family: pinyon-script;\">Phòng&nbsp;Học&nbsp;Cho&nbsp;Thuê</span></h1>','2026-04-21 16:04:33','2026-05-07 07:59:18','richtext',NULL,'about'),(33,'seo-h1-main','<h1><span style=\"font-size: 2.5rem; font-family: dancing-script;\">CHO&nbsp;THUÊ&nbsp;PHÒNG&nbsp;DẠY&nbsp;HỌC&nbsp;TẠI&nbsp;ĐÀ&nbsp;NẴNG</span></h1>','2026-04-21 16:04:33','2026-05-06 17:03:48','richtext',NULL,'about'),(34,'amenities-content','<h2 style=\"text-align: center;\"><span style=\"font-size: 2.5rem;\">Đầy&nbsp;đủ&nbsp;các&nbsp;tiện&nbsp;nghi&nbsp;sẵn&nbsp;sàng&nbsp;cho&nbsp;mỗi&nbsp;buổi&nbsp;học</span></h2>','2026-04-21 16:04:33','2026-05-06 15:39:34','richtext',NULL,'services'),(35,'gallery-heading','<h2><span style=\"font-family: arial; font-size: 2.5rem;\">Không&nbsp;gian&nbsp;phòng&nbsp;học&nbsp;qua&nbsp;từng&nbsp;khung&nbsp;hình</span></h2>','2026-04-21 16:04:33','2026-05-04 16:34:17','richtext',NULL,'gallery'),(36,'blog-heading','<h2><span style=\"font-size: 2.5rem;\">Kiến&nbsp;thức&nbsp;và&nbsp;kinh&nbsp;nghiệm&nbsp;thuê&nbsp;phòng&nbsp;dạy&nbsp;học</span></h2>','2026-04-21 16:04:33','2026-05-07 17:24:59','richtext',NULL,'blog'),(37,'faq-heading','<h2>Bạn hỏi - Hoa Học Trò đáp</h2>','2026-04-21 16:04:33','2026-04-22 18:22:32','richtext',NULL,'faq'),(38,'amenities-description','<p><span style=\"font-family: arial;\">Giữa&nbsp;nhịp&nbsp;sống&nbsp;hối&nbsp;hả&nbsp;của&nbsp;Đà&nbsp;Nẵng,&nbsp;Hoa&nbsp;Học&nbsp;Trò&nbsp;hiểu&nbsp;rằng&nbsp;bạn&nbsp;không&nbsp;chỉ&nbsp;tìm&nbsp;một&nbsp;phòng&nbsp;học&nbsp;trống&nbsp;để&nbsp;thuê,&nbsp;mà&nbsp;đang&nbsp;tìm&nbsp;một&nbsp;không&nbsp;gian&nbsp;đủ&nbsp;yên&nbsp;tĩnh,&nbsp;đủ&nbsp;tiện&nbsp;nghi&nbsp;và&nbsp;đủ&nbsp;chuyên&nbsp;tâm&nbsp;để&nbsp;mỗi&nbsp;buổi&nbsp;giảng&nbsp;dạy&nbsp;diễn&nbsp;ra&nbsp;trọn&nbsp;vẹn.&nbsp;Nơi&nbsp;mà&nbsp;khi&nbsp;cánh&nbsp;cửa&nbsp;khép&nbsp;lại,&nbsp;mọi&nbsp;ồn&nbsp;ào&nbsp;bên&nbsp;ngoài&nbsp;dừng&nbsp;lại,&nbsp;nhường&nbsp;chỗ&nbsp;cho&nbsp;sự&nbsp;tập&nbsp;trung&nbsp;và&nbsp;cảm&nbsp;hứng&nbsp;giảng&nbsp;dạy.</span></p><p><span style=\"font-family: arial;\">Không&nbsp;gian&nbsp;phòng&nbsp;học&nbsp;được&nbsp;bố&nbsp;trí&nbsp;bàn&nbsp;ghế&nbsp;tiêu&nbsp;chuẩn,&nbsp;bảng&nbsp;viết&nbsp;rõ&nbsp;nét,&nbsp;điều&nbsp;hòa&nbsp;hoạt&nbsp;động&nbsp;ổn&nbsp;định,&nbsp;tivi&nbsp;hỗ&nbsp;trợ&nbsp;trình&nbsp;chiếu,&nbsp;cùng&nbsp;hệ&nbsp;thống&nbsp;ánh&nbsp;sáng&nbsp;phù&nbsp;hợp&nbsp;cho&nbsp;việc&nbsp;học&nbsp;và&nbsp;wifi&nbsp;tốc&nbsp;độ&nbsp;cao.&nbsp;Tất&nbsp;cả&nbsp;được&nbsp;kiểm&nbsp;tra&nbsp;và&nbsp;sắp&nbsp;xếp&nbsp;gọn&nbsp;gàng&nbsp;trước&nbsp;mỗi&nbsp;ca&nbsp;sử&nbsp;dụng,&nbsp;giúp&nbsp;bạn&nbsp;không&nbsp;phải&nbsp;mất&nbsp;thời&nbsp;gian&nbsp;chuẩn&nbsp;bị&nbsp;hay&nbsp;điều&nbsp;chỉnh&nbsp;trong&nbsp;giờ&nbsp;học.</span></p><p><span style=\"font-family: arial;\">Hoa&nbsp;Học&nbsp;Trò&nbsp;tin&nbsp;rằng,&nbsp;một&nbsp;không&nbsp;gian&nbsp;đủ&nbsp;tâm&nbsp;sẽ&nbsp;tạo&nbsp;nên&nbsp;những&nbsp;giá&nbsp;trị&nbsp;đủ&nbsp;tầm.&nbsp;Nơi&nbsp;mà&nbsp;mỗi&nbsp;thiết&nbsp;bị&nbsp;đều&nbsp;mang&nbsp;trong&nbsp;mình&nbsp;sứ&nbsp;mệnh&nbsp;phụng&nbsp;sự&nbsp;cho&nbsp;khát&nbsp;vọng&nbsp;tri&nbsp;thức&nbsp;của&nbsp;bạn.</span></p>','2026-04-22 18:20:24','2026-05-05 03:55:58','richtext',NULL,'services'),(39,'describe-h2','<h2 style=\"text-align: center;\"><span style=\"font-family: playfair-display; font-size: 2.5rem;\">Giải&nbsp;pháp&nbsp;cho&nbsp;thuê&nbsp;phòng&nbsp;dạy&nbsp;học&nbsp;linh&nbsp;hoạt&